class _RestrictedUnpickler(pickle.Unpickler):
    """
    A restricted unpickler that only allows specific safe classes.
    Prevents arbitrary code execution via pickle deserialization.
    """

    # Built-in types that are always safe
    _SAFE_BUILTINS = {
        'builtins.dict',
        'builtins.list',
        'builtins.tuple',
        'builtins.set',
        'builtins.frozenset',
        'builtins.str',
        'builtins.bytes',
        'builtins.int',
        'builtins.float',
        'builtins.bool',
        'builtins.complex',
        'builtins.type',
        'builtins.range',
        'builtins.slice',
        'builtins.bytearray',
        'collections.OrderedDict',
        'collections.defaultdict',
        'datetime.datetime',
        'datetime.date',
        'datetime.time',
        'datetime.timedelta',
        'decimal.Decimal',
    }

    def __init__(self, file, *, allowed_classes=None):
        super().__init__(file)
        self._allowed_classes = allowed_classes or set()

    def find_class(self, module: str, name: str) -> type:
        full_name = f"{module}.{name}"

        if full_name in self._SAFE_BUILTINS:
            return super().find_class(module, name)

        if full_name in self._allowed_classes:
            return super().find_class(module, name)

        raise pickle.UnpicklingError(
            f"Deserialization of '{full_name}' is not allowed. "
            f"Only registered safe classes can be deserialized."
        )


