class ThemeSettings:
    """Example custom object that can be stored in preferences."""

    def __init__(self, name: str, primary_color: str, font_size: int):
        if not isinstance(name, str) or len(name) > 100:
            raise ValueError("Theme name must be a string of at most 100 characters")
        if not isinstance(primary_color, str) or len(primary_color) > 20:
            raise ValueError("Primary color must be a string of at most 20 characters")
        if not isinstance(font_size, int) or not (6 <= font_size <= 72):
            raise ValueError("Font size must be an integer between 6 and 72")

        self.name = name
        self.primary_color = primary_color
        self.font_size = font_size

    def __eq__(self, other):
        if not isinstance(other, ThemeSettings):
            return NotImplemented
        return (self.name == other.name and
                self.primary_color == other.primary_color and
                self.font_size == other.font_size)

    def __repr__(self):
        return (f"ThemeSettings(name={self.name!r}, "
                f"primary_color={self.primary_color!r}, "
                f"font_size={self.font_size!r})")


