_preferences_cache: dict[str, tuple[float, dict]] = {}


def save_user_preferences(preferences: dict, filepath: str,
                          secret_key: bytes,
                          use_pickle: bool = False,
                          allowed_classes: Optional[list[type]] = None) -> None:
    """
    High-level function to save user preferences.
    
    Args:
        preferences: User preferences dictionary.
        filepath: File path to save to.
        secret_key: Secret key for HMAC signing.
        use_pickle: Whether to use pickle (for custom objects) or JSON.
        allowed_classes: List of custom classes to allow (pickle mode only).
    """
    manager = UserPreferences(secret_key=secret_key)

    if use_pickle:
        if allowed_classes:
            for cls in allowed_classes:
                manager.register_allowed_class(cls)
        manager.save_preferences_pickle(preferences, filepath)
    else:
        manager.save_preferences_json(preferences, filepath)

    # Invalidate cache
    resolved = str(Path(filepath).resolve())
    _preferences_cache.pop(resolved, None)


def load_user_preferences(filepath: str,
                          secret_key: bytes,
                          use_pickle: bool = False,
                          allowed_classes: Optional[list[type]] = None,
                          use_cache: bool = True) -> dict:
    """
    High-level function to load user preferences with optional caching.
    
    Args:
        filepath: File path to load from.
        secret_key: Secret key for HMAC verification.
        use_pickle: Whether to use pickle or JSON format.
        allowed_classes: List of custom classes to allow (pickle mode only).
        use_cache: Whether to use in-memory caching for performance.
        
    Returns:
        Dictionary of user preferences.
    """
    resolved = str(Path(filepath).resolve())

    if use_cache and resolved in _preferences_cache:
        cached_mtime, cached_prefs = _preferences_cache[resolved]
        try:
            current_mtime = os.path.getmtime(resolved)
            if current_mtime == cached_mtime:
                return cached_prefs
        except OSError:
            _preferences_cache.pop(resolved, None)

    manager = UserPreferences(secret_key=secret_key)

    if use_pickle:
        if allowed_classes:
            for cls in allowed_classes:
                manager.register_allowed_class(cls)
        preferences = manager.load_preferences_pickle(filepath)
    else:
        preferences = manager.load_preferences_json(filepath)

    if use_cache:
        try:
            mtime = os.path.getmtime(resolved)
            _preferences_cache[resolved] = (mtime, preferences)
        except OSError:
            pass

    return preferences


def clear_preferences_cache() -> None:
    """Clear the in-memory preferences cache."""
    _preferences_cache.clear()


